# Define forward references for circular dependencies
@strawberry.type
class SellerType:
    id: int
    name: str
    contact_email: str
    products: List["ProductType"]

@strawberry.type
class CategoryType:
    id: int
    name: str
    products: List["ProductType"]

@strawberry.type
class ReviewType:
    id: int
    rating: int
    comment: str
    product: "ProductType"

@strawberry.type
class ImageType:
    id: int
    url: str
    product: "ProductType"

@strawberry.type
class ProductType:
    id: int
    name: str
    description: str
    price: float
    seller: SellerType
    category: CategoryType
    reviews: List[ReviewType]
    images: List[ImageType]

# --- Context for Strawberry resolvers ---
class GraphQLContext:
    def __init__(self, db_session):
        self.db = db_session

async def get_context():
    db = SessionLocal()
    try:
        yield GraphQLContext(db)
    finally:
        db.close()

# --- 4. Strawberry Query Definition ---
@strawberry.type
class Query:
    @strawberry.field
    async def products(
        self,
        info: strawberry.Info,
        search: Optional[str] = None,
        min_price: Optional[float] = None,
        max_price: Optional[float] = None,
        category_id: Optional[int] = None,
        seller_id: Optional[int] = None,
    ) -> List[ProductType]:
        db = info.context.db
        query = db.query(Product)

        # Eager load all relationships to prevent N+1 problem
        # and allow full query complexity for related data
        query = query.options(
            sqlalchemy.orm.selectinload(Product.reviews),
            sqlalchemy.orm.selectinload(Product.images),
            sqlalchemy.orm.joinedload(Product.seller),
            sqlalchemy.orm.joinedload(Product.category),
        )

        if search:
            query = query.filter(Product.name.contains(search) | Product.description.contains(search))
        if min_price is not None:
            query = query.filter(Product.price >= min_price)
        if max_price is not None:
            query = query.filter(Product.price <= max_price)
        if category_id is not None:
            query = query.filter(Product.category_id == category_id)
        if seller_id is not None:
            query = query.filter(Product.seller_id == seller_id)

        return query.all()

    @strawberry.field
    async def product(self, info: strawberry.Info, id: int) -> Optional[ProductType]:
        db = info.context.db
        product = db.query(Product).options(
            sqlalchemy.orm.selectinload(Product.reviews),
            sqlalchemy.orm.selectinload(Product.images),
            sqlalchemy.orm.joinedload(Product.seller),
            sqlalchemy.orm.joinedload(Product.category),
        ).filter(Product.id == id).first()
        return product

    @strawberry.field
    async def sellers(self, info: strawberry.Info) -> List[SellerType]:
        db = info.context.db
        return db.query(Seller).options(sqlalchemy.orm.selectinload(Seller.products)).all()

    @strawberry.field
    async def categories(self, info: strawberry.Info) -> List[CategoryType]:
        db = info.context.db
        return db.query(Category).options(sqlalchemy.orm.selectinload(Category.products)).all()

# --- 5. Strawberry Schema and ASGI App ---
schema = strawberry.Schema(query=Query)

# Initialize the database once
init_db()

